const payload = $input.first().json.body || {};

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const parseDate = (value) => {
  if (!value) return null;
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
};

const asDate = parseDate(payload.start_time);
const formatDate = (value) => {
  const date = value instanceof Date ? value : parseDate(value);
  if (!date) return String(value || '—');
  return date.toLocaleDateString('de-DE', { day: '2-digit', month: 'long', year: 'numeric' });
};
const formatTime = (value) => {
  const date = value instanceof Date ? value : parseDate(value);
  if (!date) return String(value || '—');
  return date.toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit', hour12: false });
};

const type = payload.type || '24h';
const customerName = payload.customer_name || 'Kunde';
const serviceName = payload.service_name || 'Termin';
const stylistName = payload.stylist_name || 'Ihr BookCut Team';
const salonName = payload.salon_name || 'BookCut';
const salonPhone = payload.salon_phone || '';
const salonEmail = payload.salon_email || 'termin@bookcut.app';
const appointmentDate = formatDate(asDate || payload.start_time);
const appointmentTime = formatTime(asDate || payload.start_time);
const contactLine = [salonPhone, salonEmail].filter(Boolean).join(' · ') || 'termin@bookcut.app';

const palette = {
  ink: '#0F1C3F',
  inkSoft: '#425066',
  gold: '#C9A84C',
  sand: '#F4F1EA',
  card: '#F7F8FB',
  border: '#E6EAF1',
};

const content = {
  confirm: {
    eyebrow: 'Booking bestätigt',
    headline: 'Ihr Termin bei BookCut ist fix eingeplant.',
    intro: 'Vielen Dank für Ihre Buchung. Wir haben alles für Ihren Besuch vorbereitet und freuen uns darauf, Sie im Salon willkommen zu heißen.',
    note: 'Wenn Sie noch etwas anpassen möchten, antworten Sie einfach auf diese E-Mail. Wir kümmern uns schnell darum.',
    subject: 'Ihr Termin wurde bestätigt',
  },
  '24h': {
    eyebrow: 'Erinnerung für morgen',
    headline: 'Morgen sehen wir uns bei BookCut.',
    intro: 'Nur eine kurze Erinnerung: Ihr gebuchter Termin steht morgen an. Hier finden Sie alle Details noch einmal kompakt auf einen Blick.',
    note: 'Bitte planen Sie für Ihre Ankunft ein paar Minuten Vorlauf ein. Falls Sie verschieben müssen, geben Sie uns bitte rechtzeitig Bescheid.',
    subject: `Erinnerung: Ihr Termin am ${appointmentDate}`,
  },
  '2h': {
    eyebrow: 'Ihr Termin startet gleich',
    headline: 'In Kürze geht es los.',
    intro: 'Ihr Termin rückt näher. Jetzt ist ein guter Moment, um entspannt loszufahren und sich kurz auf Ihren Besuch bei BookCut einzustimmen.',
    note: 'Falls kurzfristig etwas dazwischenkommt, informieren Sie uns bitte so schnell wie möglich.',
    subject: `Ihr Termin heute um ${appointmentTime}`,
  },
};

const selected = content[type] || content['24h'];
const subject = payload.emailSubject || selected.subject;
const text = payload.emailBody || [
  `Hallo ${customerName},`,
  '',
  selected.intro,
  '',
  `Datum: ${appointmentDate}`,
  `Uhrzeit: ${appointmentTime}`,
  `Service: ${serviceName}`,
  `Stylist: ${stylistName}`,
  '',
  selected.note,
  '',
  `BookCut`,
  contactLine,
].join('\n');

const html = payload.emailHtml || `<!DOCTYPE html>
<html lang="de">
  <body style="margin:0;padding:0;background:${palette.sand};font-family:'Plus Jakarta Sans',Arial,Helvetica,sans-serif;color:${palette.ink};">
    <div style="display:none;max-height:0;overflow:hidden;opacity:0;">${escapeHtml(selected.subject)} – ${escapeHtml(serviceName)} am ${escapeHtml(appointmentDate)} um ${escapeHtml(appointmentTime)}</div>
    <table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background:${palette.sand};padding:28px 12px;">
      <tr>
        <td align="center">
          <table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="max-width:680px;background:#ffffff;border-radius:26px;overflow:hidden;box-shadow:0 22px 64px rgba(15,28,63,0.14);">
            <tr>
              <td style="padding:20px 28px;background:${palette.ink};color:#ffffff;">
                <table role="presentation" width="100%" cellspacing="0" cellpadding="0">
                  <tr>
                    <td align="left" style="font-size:13px;letter-spacing:0.22em;text-transform:uppercase;color:rgba(255,255,255,0.72);font-weight:700;">BookCut</td>
                    <td align="right" style="font-size:12px;color:rgba(255,255,255,0.72);">${escapeHtml(selected.eyebrow)}</td>
                  </tr>
                </table>
              </td>
            </tr>
            <tr>
              <td style="background:linear-gradient(135deg, ${palette.ink} 0%, #182B62 60%, ${palette.gold} 170%);padding:36px 32px 42px;">
                <div style="display:inline-block;padding:8px 14px;border-radius:999px;border:1px solid rgba(255,255,255,0.18);background:rgba(255,255,255,0.04);font-size:12px;letter-spacing:0.14em;text-transform:uppercase;color:#F4E2A9;font-weight:700;">${escapeHtml(selected.eyebrow)}</div>
                <h1 style="margin:18px 0 12px;font-size:34px;line-height:1.12;color:#ffffff;font-weight:800;letter-spacing:-0.03em;">${escapeHtml(selected.headline)}</h1>
                <p style="margin:0;max-width:520px;font-size:16px;line-height:1.75;color:rgba(255,255,255,0.84);">${escapeHtml(selected.intro)}</p>
              </td>
            </tr>
            <tr>
              <td style="padding:32px;">
                <p style="margin:0 0 18px;font-size:16px;line-height:1.75;color:${palette.inkSoft};">Hallo <strong style="color:${palette.ink};">${escapeHtml(customerName)}</strong>,</p>
                <table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="border-collapse:separate;border-spacing:0 12px;">
                  <tr>
                    <td style="width:33.33%;padding:18px 16px;background:${palette.card};border:1px solid ${palette.border};border-radius:18px;vertical-align:top;">
                      <div style="font-size:11px;letter-spacing:0.14em;text-transform:uppercase;color:#8C7743;font-weight:700;margin-bottom:8px;">Datum</div>
                      <div style="font-size:18px;line-height:1.4;color:${palette.ink};font-weight:800;">${escapeHtml(appointmentDate)}</div>
                    </td>
                    <td style="width:33.33%;padding:18px 16px;background:${palette.card};border:1px solid ${palette.border};border-radius:18px;vertical-align:top;">
                      <div style="font-size:11px;letter-spacing:0.14em;text-transform:uppercase;color:#8C7743;font-weight:700;margin-bottom:8px;">Uhrzeit</div>
                      <div style="font-size:18px;line-height:1.4;color:${palette.ink};font-weight:800;">${escapeHtml(appointmentTime)}</div>
                    </td>
                    <td style="width:33.33%;padding:18px 16px;background:${palette.card};border:1px solid ${palette.border};border-radius:18px;vertical-align:top;">
                      <div style="font-size:11px;letter-spacing:0.14em;text-transform:uppercase;color:#8C7743;font-weight:700;margin-bottom:8px;">Service</div>
                      <div style="font-size:18px;line-height:1.4;color:${palette.ink};font-weight:800;">${escapeHtml(serviceName)}</div>
                    </td>
                  </tr>
                </table>

                <div style="margin-top:18px;padding:24px;background:linear-gradient(180deg,#FFF9EC 0%,#FFFDF6 100%);border:1px solid rgba(201,168,76,0.28);border-radius:22px;">
                  <div style="font-size:12px;letter-spacing:0.14em;text-transform:uppercase;color:#8C7743;font-weight:700;margin-bottom:12px;">Ihr Termin im Überblick</div>
                  <p style="margin:0 0 10px;font-size:16px;line-height:1.75;color:${palette.inkSoft};"><strong style="color:${palette.ink};">Stylist:</strong> ${escapeHtml(stylistName)}</p>
                  <p style="margin:0;font-size:16px;line-height:1.75;color:${palette.inkSoft};"><strong style="color:${palette.ink};">Kontakt:</strong> ${escapeHtml(contactLine)}</p>
                </div>

                <div style="margin-top:22px;padding:18px 20px;border-left:4px solid ${palette.gold};background:#FBFCFE;border-radius:0 16px 16px 0;">
                  <p style="margin:0;font-size:15px;line-height:1.8;color:${palette.inkSoft};">${escapeHtml(selected.note)}</p>
                </div>
              </td>
            </tr>
            <tr>
              <td style="padding:0 32px 32px;">
                <div style="height:1px;background:linear-gradient(90deg,rgba(15,28,63,0),rgba(15,28,63,0.14),rgba(15,28,63,0));margin-bottom:20px;"></div>
                <table role="presentation" width="100%" cellspacing="0" cellpadding="0">
                  <tr>
                    <td style="font-size:14px;line-height:1.8;color:#7B8594;">
                      <strong style="color:${palette.ink};font-size:15px;">${escapeHtml(salonName)}</strong><br>
                      ${escapeHtml(contactLine)}
                    </td>
                    <td align="right" style="font-size:12px;color:#8B93A2;letter-spacing:0.08em;text-transform:uppercase;">Book smarter. Look sharper.</td>
                  </tr>
                </table>
              </td>
            </tr>
          </table>
        </td>
      </tr>
    </table>
  </body>
</html>`;

return [{
  json: {
    body: payload,
    channel: payload.channel || 'email',
    toEmail: payload.customer_email || null,
    subject,
    text,
    html,
  },
}];
